import { Item } from '@/wishlist/data/models/wishlist';

interface ProductLike {
  sku: string;
  optionUIDs?: string[];
}

/**
 * Helper function to compare wishlist items by their SKU and selected options
 */
export function isMatchingWishlistItem(
  wishlistItem: Item,
  product: ProductLike
): boolean {
  // Compare SKUs first for early return
  if (wishlistItem.product.sku !== product.sku) {
    return false;
  }

  // Compare selected options
  const wishlistItemOptions =
    wishlistItem.selectedOptions
      ?.map((option: any) => option.uid)
      .filter((uid: any) => !!uid)
      .sort() || [];
  const productOptionUIDs = (product.optionUIDs || [])
    .filter((uid: any) => !!uid)
    .sort();

  // If options match (or both are empty), items are considered matching
  return (
    JSON.stringify(wishlistItemOptions) === JSON.stringify(productOptionUIDs)
  );
}
