import { fetchGraphQl } from '@/wishlist/api';
import { state } from '@/wishlist/lib/state';
import { handleFetchError } from '@/wishlist/lib/fetch-error';
import { REMOVE_PRODUCTS_FROM_WISHLIST_MUTATION } from './graphql/removeProductsFromWishlistMutation';
import { Item, Wishlist } from '@/wishlist/data/models/wishlist';
import { events } from '@adobe-commerce/event-bus';
import { getPersistedWishlistData } from '@/wishlist/lib/persisted-data';
import { isMatchingWishlistItem } from '@/wishlist/lib/wishlist-item-comparator';

export const removeProductsFromWishlist = async (
  items: Array<Item>
): Promise<Wishlist | null> => {
  const wishlist = getPersistedWishlistData();
  const updatedWishlist = {
    ...wishlist,
    items: wishlist.items?.filter((wishlistItem: any) => {
      return !items.some((item) =>
        isMatchingWishlistItem(wishlistItem, {
          sku: item.product.sku,
          optionUIDs: item.selectedOptions?.map((option: any) => option.uid),
        })
      );
    }),
  };

  if (state.authenticated) {
    if (!state.wishlistId) {
      throw Error('Wishlist ID is not set');
    }

    const itemIds = items.map((item) => item.id);
    const { errors, data } = await fetchGraphQl(
      REMOVE_PRODUCTS_FROM_WISHLIST_MUTATION,
      {
        variables: { wishlistId: state.wishlistId, wishlistItemsIds: itemIds },
      }
    );

    const _errors = [
      ...(data?.removeProductsFromWishlist?.user_errors ?? []),
      ...(errors ?? []),
    ];

    // restore wishlist if removing item failed:
    if (_errors.length > 0) {
      events.emit('wishlist/data', wishlist);
      return handleFetchError(_errors);
    }
  }

  updatedWishlist.items_count = updatedWishlist.items?.length;
  events.emit('wishlist/data', updatedWishlist);

  return null;
};
