import { fetchGraphQl } from '@/wishlist/api';
import { state } from '@/wishlist/lib/state';
import { handleFetchError } from '@/wishlist//lib/fetch-error';

import { UPDATE_PRODUCTS_IN_WISHLIST_MUTATION } from './graphql/updateProductsInWishlistMutation';
import { Wishlist } from '@/wishlist/data/models/wishlist';
import { transformWishlist } from '@/wishlist/data/transforms';

export const updateProductsInWishlist = async (
  items: {
    wishlistItemId: string;
    quantity: number;
    description: string;
    selectedOptions?: string[];
    enteredOptions?: { uid: string; value: string }[];
  }[]
): Promise<Wishlist | null> => {
  const wishlistId = state.wishlistId;

  if (!wishlistId) {
    throw Error('Wishlist ID is not set');
  }

  return fetchGraphQl(UPDATE_PRODUCTS_IN_WISHLIST_MUTATION, {
    variables: {
      wishlistId,
      wishlistItems: items.map(
        ({
          wishlistItemId,
          quantity,
          description,
          selectedOptions: selected_options,
          enteredOptions: entered_options,
        }) => ({
          wishlistItemId,
          quantity,
          description,
          selected_options,
          entered_options,
        })
      ),
    },
  }).then(({ errors, data }) => {
    // handle errors
    const _errors = [
      ...(data?.updateProductsInWishlist?.user_errors ?? []),
      ...(errors ?? []),
    ];

    if (_errors.length > 0) return handleFetchError(_errors);

    return transformWishlist(data.updateProductsInWishlist.wishlist);
  });
};
