import { StoreConfigModel } from '@/wishlist/data/models/store-config';
import { getCookie } from '@/wishlist/lib/cookies';

type State = {
  wishlistId: string | null;
  initializing?: boolean;
  isLoading?: boolean;
  locale?: string;
  config?: StoreConfigModel | null;
  authenticated: boolean;
  storeCode?: string;
};

const _state: State = (() => {
  return {
    wishlistId: null,
    authenticated: false,
    isLoading: true,
  };
})();

const getWishlistCookieName = (): string =>
  _state.storeCode && _state.storeCode !== 'default'
    ? `DROPIN__WISHLIST__WISHLIST-ID__${_state.storeCode}`
    : 'DROPIN__WISHLIST__WISHLIST-ID';

// Proxy state to allow reactivity
export const state = new Proxy(_state, {
  set(target, key, value) {
    // @ts-ignore
    target[key] = value;

    if (key === 'wishlistId') {
      const cookieName = getWishlistCookieName();

      // only update cookie if value has changed
      if (value === state.wishlistId) return true;

      if (value === null) {
        document.cookie = `${cookieName}=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/`;
        return true;
      }

      // set expiration date
      const expires = new Date();
      expires.setDate(expires.getDate() + 30);
      document.cookie = `${cookieName}=${value}; expires=${expires.toUTCString()}; path=/`;
    }

    return Reflect.set(target, key, value);
  },
  get(target, key) {
    if (key === 'wishlistId') {
      return getCookie(getWishlistCookieName());
    }

    return target[key as keyof State];
  },
});
