import { GET_WISHLIST_BY_ID_QUERY } from '@/wishlist/api/getWishlistById/graphql/getWishlistById.graphql';
import { Wishlist } from '@/wishlist/data/models';
import { transformWishlist } from '@/wishlist/data/transforms';
import { state } from '@/wishlist/lib/state';
import { fetchGraphQl, getPersistedWishlistData } from '@/wishlist/api';
import { handleFetchError } from '@/wishlist/lib/fetch-error';
import { events } from '@adobe-commerce/event-bus';

export const getWishlistById = async (
  wishlistId: string
): Promise<void | Wishlist | null> => {
  // When the user is not authenticated, we just have a single wishlist
  // There is no necessity to check any IDs
  if (!state.authenticated) {
    return getPersistedWishlistData();
  }

  if (!wishlistId) {
    throw Error('Wishlist ID is not set');
  }

  // @ts-ignore
  return fetchGraphQl(GET_WISHLIST_BY_ID_QUERY, {
    variables: {
      wishlistId,
    },
  }).then(({ errors, data }) => {
    if (errors) return handleFetchError(errors);

    if (!data?.customer?.wishlist_v2) {
      return null;
    }

    const payload = transformWishlist(data.customer.wishlist_v2);
    events.emit('wishlist/data', payload);
    return payload;
  });
};
