import { Wishlist } from '@/wishlist/data/models';
import { state } from '@/wishlist/lib/state';
import { isMatchingWishlistItem } from '@/wishlist/lib/wishlist-item-comparator';

const WISHLIST_KEY_BASE = 'DROPIN__WISHLIST__WISHLIST__DATA';

const getWishlistKey = (): string =>
  state.storeCode && state.storeCode !== 'default'
    ? `${WISHLIST_KEY_BASE}__${state.storeCode}`
    : WISHLIST_KEY_BASE;

export function setPersistedWishlistData(data: Wishlist | null) {
  const $storage = state.authenticated ? sessionStorage : localStorage;
  const key = getWishlistKey();
  if (data) {
    try {
      $storage.setItem(key, JSON.stringify(data));
    } catch (error) {
      if (isQuotaExceededError(error)) {
        console.error('Storage quota exceeded:', error);
      } else {
        console.error('Error saving wishlist:', error);
      }
    }
  } else {
    $storage.removeItem(key);
  }
}

const isQuotaExceededError = (error: unknown) => {
  //https://mmazzarolo.com/blog/2022-06-25-local-storage-status/
  return error instanceof DOMException && error.name === 'QuotaExceededError';
};

export function getPersistedWishlistData(
  guest: boolean = false
): Wishlist | {} {
  const $storage =
    state.authenticated && !guest ? sessionStorage : localStorage;
  const key = getWishlistKey();
  try {
    const wishlist = $storage.getItem(key);
    return wishlist ? JSON.parse(wishlist) : { id: '', items: [] };
  } catch (error) {
    console.error('Error retrieving wishlist:', error);
    return { id: '', items: [] };
  }
}

export function clearPersistedLocalStorage() {
  localStorage.removeItem(getWishlistKey());
}

export function getWishlistItemFromStorage(
  productSku: string,
  optionUIDs: string[] = []
) {
  const storage = state.authenticated ? sessionStorage : localStorage;
  const key = getWishlistKey();
  const raw = storage.getItem(key);
  const wishlist = raw ? JSON.parse(raw) : { id: '', items: [] };

  return wishlist?.items?.find((item: any) =>
    isMatchingWishlistItem(item, {
      sku: productSku,
      optionUIDs,
    })
  );
}
