import { WISHLIST_ITEM_FRAGMENT } from '@/wishlist/api/fragments';

export const GET_WISHLIST_BY_ID_QUERY = `
  query GET_WISHLIST_BY_ID_QUERY(
    $wishlistId: ID!,
  ) {
    customer {
      wishlist_v2(id: $wishlistId) {
        id
        updated_at
        sharing_code
        items_count
        items_v2 {
          items {
            ...WISHLIST_ITEM_FRAGMENT
          }
        }
      }
    }
  }

${WISHLIST_ITEM_FRAGMENT}
`;
